from __future__ import annotations
from typing import Any
from cnsv.live.live_decision_rules import compute_manual_decision_status
def build_live_state_payload(reports:dict[str,Any],availability:dict[str,Any])->dict[str,Any]:
 data=reports.get("data_report") or {}; feature=reports.get("feature_report") or {}; baseline=reports.get("baseline_model_report") or {}; bv=reports.get("baseline_validation_report") or {}; path=reports.get("path_distribution_report") or {}; pv=reports.get("path_validation_report") or {}; backtest=reports.get("observation_backtest_report") or {}; support=reports.get("human_decision_support_report") or {}; risk=reports.get("risk_explanation_report") or {}
 decision=compute_manual_decision_status(availability,risk); pvf=_feature(feature,"price_volume"); mf=_feature(feature,"moneyflow"); trend=_feature(feature,"trend"); vol=_feature(feature,"volatility"); minute=_feature(feature,"minute_structure")
 return {"live_state_overview":{"latest_trade_date":_latest_trade_date(data,feature,risk),"latest_close":pvf.get("latest_close"),"data_status":_status(data,"validation"),"feature_status":_status(feature,"feature_quality"),"baseline_status":_status(baseline,"baseline_quality"),"baseline_validation_status":_status(bv,"baseline_validation_quality"),"path_status":_status(path,"path_quality"),"path_validation_status":_status(pv,"path_validation_quality"),"backtest_status":_status(backtest,"observation_backtest_quality"),"support_status":_status(support,"human_decision_support_quality"),"risk_status":_status(risk,"risk_explanation_quality"),"overall_system_status":decision["overall_system_status"],"manual_decision_status":decision["manual_decision_status"],"manual_review_required":decision["manual_review_required"],"status_reasons":decision["status_reasons"]},"evidence_dashboard":{"evidence_availability":availability,"missing_evidence":availability.get("missing_reports",[]),"stale_evidence":availability.get("stale_evidence",[]),"failed_quality_gates":availability.get("failed_quality_gates",[]),"warning_quality_gates":availability.get("warning_quality_gates",[])},"current_state_card":{"current_price_context":{"latest_close":pvf.get("latest_close"),"latest_pct_chg":pvf.get("latest_pct_chg"),"ma5":pvf.get("ma5"),"ma20":pvf.get("ma20")},"trend_state_context":{"trend_state":trend.get("trend_state") or (support.get("current_state_summary") or {}).get("trend_state"),"ma5_minus_ma20":trend.get("ma5_minus_ma20"),"close_above_ma20":trend.get("close_above_ma20")},"volatility_state_context":{"volatility_state":vol.get("volatility_state") or (support.get("current_state_summary") or {}).get("volatility_state"),"realized_vol_20d":vol.get("realized_vol_20d"),"atr_14d":vol.get("atr_14d")},"flow_strength_context":{"flow_strength_basic":mf.get("flow_strength_basic") or mf.get("moneyflow_strength_basic") or (support.get("current_state_summary") or {}).get("flow_strength_basic"),"main_force_net":mf.get("main_force_net"),"net_mf_ratio":mf.get("net_mf_ratio"),"flow_strength_score":mf.get("flow_strength_score"),"price_flow_confirm":mf.get("price_flow_confirm"),"price_flow_divergence":mf.get("price_flow_divergence"),"volume_flow_confirm":mf.get("volume_flow_confirm")},"minute_structure_context":{"latest_intraday_close":minute.get("latest_intraday_close"),"intraday_range_pct":minute.get("intraday_range_pct"),"close_position_in_day_range":minute.get("close_position_in_day_range")},"state_sample_context":_state_samples(baseline,path)},"path_observation_card":_path_observation(path,pv,backtest),"risk_explanation_card":{"overall_risk_level":(risk.get("overall_risk_summary") or {}).get("overall_risk_level"),"risk_confidence":(risk.get("overall_risk_summary") or {}).get("risk_confidence"),"primary_risk_sources":(risk.get("overall_risk_summary") or {}).get("primary_risk_sources",[]),"secondary_risk_sources":(risk.get("overall_risk_summary") or {}).get("secondary_risk_sources",[]),"risk_scenario_cards":risk.get("risk_scenario_cards",[]),"risk_review_checklist":risk.get("risk_review_checklist",[])},"evidence_conflict_card":{"evidence_conflict":((risk.get("evidence_conflict_risk_explanation") or {}).get("evidence_conflict")),"conflict_reasons":(risk.get("evidence_conflict_risk_explanation") or {}).get("risk_evidence",[]),"model_disagreement_points":(support.get("model_consistency_summary") or {}).get("model_disagreement_points",[]),"risk_conflict_points":(risk.get("risk_source_breakdown") or {}).get("evidence_conflict_risk",{}),"manual_confirmation_required":bool((risk.get("evidence_conflict_risk_explanation") or {}).get("evidence_conflict"))}}
def _feature(feature:dict[str,Any],key:str)->dict[str,Any]: return feature.get(key) or (feature.get("features") or {}).get(key) or {}
def _status(report:dict[str,Any],key:str)->str:
 if not report: return "MISSING"
 if key=="validation": return str((report.get("validation") or report.get("data_quality") or {}).get("status") or "N/A")
 return str((report.get(key) or {}).get("status") or "N/A")
def _latest_trade_date(*reports:dict[str,Any])->str:
 for r in reports:
  v=(r.get("meta") or {}).get("latest_trade_date") or (r.get("data_manifest") or {}).get("latest_trade_date")
  if v: return str(v)
 return "N/A"
def _state_samples(baseline:dict[str,Any],path:dict[str,Any])->dict[str,Any]:
 b2=(((baseline.get("baseline_models") or {}).get("B2_state_grouped_distribution") or {}).get("horizons") or {}); p2=(((path.get("path_models") or {}).get("P2_state_conditional_path") or {}).get("horizons") or {})
 return {"B2_state_sample_size":{k:v.get("state_sample_size") for k,v in b2.items() if isinstance(v,dict)},"P2_state_sample_size":{k:v.get("state_sample_size") for k,v in p2.items() if isinstance(v,dict)},"P2_role":"auxiliary_only"}
def _path_observation(path:dict[str,Any],validation:dict[str,Any],backtest:dict[str,Any])->dict[str,Any]:
 p0=(((path.get("path_models") or {}).get("P0_baseline_path") or {}).get("horizons") or {}); p1=(((path.get("path_models") or {}).get("P1_volatility_adjusted_path") or {}).get("horizons") or {})
 return {"terminal_distribution_summary":_horizon_summary(p0,["terminal_return_p50","terminal_return_p10","terminal_return_p90"]),"touch_up_summary":_horizon_summary(p1 or p0,["touch_up_5pct_prob","touch_up_10pct_prob"]),"touch_down_summary":_horizon_summary(p1 or p0,["touch_down_5pct_prob","touch_down_10pct_prob"]),"drawdown_summary":_horizon_summary(p1 or p0,["max_drawdown_p50","max_drawdown_p90"]),"path_validation_summary":validation.get("validation_summary") or validation.get("path_validation_quality") or {},"observation_backtest_support":{"quality":backtest.get("observation_backtest_quality",{}),"scope":backtest.get("backtest_scope",{}),"model_comparison":backtest.get("model_comparison",{})}}
def _horizon_summary(horizons:dict[str,Any],keys:list[str])->dict[str,Any]: return {h:{k:r.get(k) for k in keys if isinstance(r,dict) and k in r} for h,r in horizons.items()}
